// Build OpenRouter API request body for Claude Haiku classification
try {
  const input = $json.body || $json;
  const complaint = input.complaint || '';
  const citizenEmail = input.citizen_email || '';
  const citizenName = input.citizen_name || '';

  const promptLines = [
    'You are a city services dispatcher for Georgetown, Guyana. Classify the following citizen complaint.',
    '',
    'Complaint: ' + complaint,
    '',
    'DEPARTMENT ROUTING RULES (follow exactly):',
    '- drainage or flooding -> "D&I Authority - Georgetown Division"',
    '- garbage -> "M&CC Sanitation - City Constabulary"',
    '- pothole -> "Ministry of Public Works - Georgetown District"',
    '- structural -> "Mayor & City Council - Infrastructure Division"',
    '',
    'Return ONLY valid JSON with these exact fields:',
    '{',
    '  "issue_type": "drainage|garbage|pothole|flooding|structural",',
    '  "urgency": "low|medium|high|critical",',
    '  "location_extracted": "extracted street or area name, or Location not specified",',
    '  "department": "use the department from the routing rules above",',
    '  "dispatch_summary": "2-sentence plain English dispatch summary for the department",',
    '  "citizen_message": "1-sentence plain English confirmation for the citizen"',
    '}'
  ];
  const prompt = promptLines.join('\n');

  const requestBody = JSON.stringify({
    model: 'anthropic/claude-3.5-haiku',
    messages: [{ role: 'user', content: prompt }],
    max_tokens: 500,
    temperature: 0.1
  });

  return [{ json: { requestBody: requestBody, complaint: complaint, citizen_email: citizenEmail, citizen_name: citizenName } }];
} catch (error) {
  return [{ json: { error: error.message } }];
}

// Parse AI classification response and generate ticket
try {
  const aiResponse = $json;
  let content = '';

  if (aiResponse.choices && aiResponse.choices.length > 0) {
    content = aiResponse.choices[0].message.content;
  }

  let classification;
  try {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    classification = JSON.parse(jsonMatch ? jsonMatch[0] : content);
  } catch (e) {
    classification = {
      issue_type: 'structural',
      urgency: 'medium',
      location_extracted: 'Location not specified',
      department: 'Mayor & City Council - Infrastructure Division',
      dispatch_summary: 'Complaint received. Routing to infrastructure team for assessment.',
      citizen_message: 'Your complaint has been received and will be reviewed by our team.'
    };
  }

  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  const rand = String(Math.floor(1000 + Math.random() * 9000));
  const ticketId = 'GEO-' + year + '-' + month + day + '-' + rand;

  const responseWindows = {
    drainage: '24 hours',
    flooding: '24 hours',
    garbage: '48 hours',
    pothole: '72 hours',
    structural: '72 hours'
  };
  const responseWindow = responseWindows[classification.issue_type] || '72 hours';

  const complaint = $('Build AI Request').item.json.complaint;
  const citizenEmail = $('Build AI Request').item.json.citizen_email;
  const citizenName = $('Build AI Request').item.json.citizen_name;

  return [{
    json: {
      ticket_id: ticketId,
      date: year + '-' + month + '-' + day,
      complaint: complaint,
      citizen_email: citizenEmail,
      citizen_name: citizenName,
      issue_type: classification.issue_type,
      urgency: classification.urgency,
      location: classification.location_extracted,
      department: classification.department,
      dispatch_summary: classification.dispatch_summary,
      citizen_message: classification.citizen_message,
      response_window: responseWindow,
      status: 'Open'
    }
  }];
} catch (error) {
  return [{ json: { error: error.message, ticket_id: 'GEO-ERROR-0000', status: 'Error' } }];
}

// Build flat object matching Google Sheets column headers exactly
try {
  const d = $('Parse and Build Ticket').item.json;

  return [{
    json: {
      'Ticket ID': d.ticket_id,
      'Date': d.date,
      'Complaint': d.complaint,
      'Issue Type': d.issue_type,
      'Urgency': d.urgency,
      'Location': d.location,
      'Department': d.department,
      'Dispatch Summary': d.dispatch_summary,
      'Citizen Email': d.citizen_email,
      'Status': d.status
    }
  }];
} catch (error) {
  return [{ json: { error: error.message } }];
}

// Build all message strings in Code node - no concatenation in n8n expressions (lesson #41)
try {
  const d = $('Parse and Build Ticket').item.json;

  const issueLabel = d.issue_type.charAt(0).toUpperCase() + d.issue_type.slice(1);

  const gmailSubject = 'Georgetown City Services - Ticket ' + d.ticket_id;

  const gmailLines = [
    'Dear ' + d.citizen_name + ',',
    '',
    'Thank you for reporting your concern to Georgetown City Services.',
    '',
    'Ticket Number: ' + d.ticket_id,
    'Issue Type: ' + issueLabel,
    'Location: ' + d.location,
    'Assigned To: ' + d.department,
    '',
    d.citizen_message,
    '',
    'Expected response window: ' + d.response_window,
    '',
    'You can reference your ticket number ' + d.ticket_id + ' for any follow-up inquiries.',
    '',
    'Georgetown City Services',
    'Mayor & City Council'
  ];
  const gmailBody = gmailLines.join('\n');

  const slackLines = [
    '*Georgetown City Services - New Dispatch*',
    '',
    '*Ticket:* ' + d.ticket_id,
    '*Issue:* ' + d.issue_type.toUpperCase() + ' - ' + d.urgency.toUpperCase() + ' urgency',
    '*Location:* ' + d.location,
    '*Department:* ' + d.department,
    '',
    '*Dispatch Summary:*',
    d.dispatch_summary,
    '',
    '*Citizen:* ' + d.citizen_name + ' (' + d.citizen_email + ')'
  ];
  const slackText = slackLines.join('\n');

  return [{
    json: {
      gmail_subject: gmailSubject,
      gmail_body: gmailBody,
      slack_text: slackText,
      citizen_email: d.citizen_email,
      ticket_id: d.ticket_id,
      issue_type: d.issue_type,
      urgency: d.urgency,
      department: d.department
    }
  }];
} catch (error) {
  return [{ json: { error: error.message } }];
}

// Build webhook response with ticket summary
try {
  const d = $('Parse and Build Ticket').item.json;

  return [{
    json: {
      success: true,
      ticket_id: d.ticket_id,
      issue_type: d.issue_type,
      urgency: d.urgency,
      location: d.location,
      department: d.department,
      response_window: d.response_window,
      message: d.citizen_message
    }
  }];
} catch (error) {
  return [{ json: { success: false, error: error.message } }];
}

